&= \tfrac{1}{27}((0,-7) + 10(5,\!-\!3)) + (0,7) \\
&= (\tfrac{50}{27},\tfrac{7}{27}), \\
\end{align*}
and so $(x,y,z) = \boxed{\left (\tfrac{50}{27},\tfrac{7}{27},\tfrac{2}{27} \right )}.$
